import{_ as i,c as a,o,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Fonctionnalités de la Plateforme : Modèles et Quotas | opencode-antigravity-auth","description":"Découvrez les types de modèles et le système de double quota d'Antigravity Auth. Maîtrisez le choix de modèles, la configuration Thinking et la méthode Google Search pour optimiser l'utilisation des quotas.","frontmatter":{"title":"Fonctionnalités de la Plateforme : Modèles et Quotas | opencode-antigravity-auth","sidebarTitle":"Débloquer le Système Double Quota","subtitle":"Fonctionnalités de la Plateforme : Modèles et Quotas","description":"Découvrez les types de modèles et le système de double quota d'Antigravity Auth. Maîtrisez le choix de modèles, la configuration Thinking et la méthode Google Search pour optimiser l'utilisation des quotas.","order":2},"headers":[],"relativePath":"fr/NoeFabris/opencode-antigravity-auth/platforms/index.md","filePath":"fr/NoeFabris/opencode-antigravity-auth/platforms/index.md"}`),l={name:"fr/NoeFabris/opencode-antigravity-auth/platforms/index.md"};function r(s,e,n,d,u,c){return o(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="fonctionnalites-de-la-plateforme" tabindex="-1">Fonctionnalités de la Plateforme <a class="header-anchor" href="#fonctionnalites-de-la-plateforme" aria-label="Permalink to &quot;Fonctionnalités de la Plateforme&quot;">​</a></h1><p>Ce chapitre vous aide à approfondir votre compréhension des modèles, du système de quotas et des fonctionnalités de la plateforme pris en charge par le plugin Antigravity Auth. Vous apprendrez à choisir le modèle approprié, à configurer les capacités Thinking, à activer Google Search et à maximiser l&#39;utilisation des quotas.</p><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Avant de commencer, veuillez confirmer</p><p>Avant d&#39;étudier ce chapitre, assurez-vous d&#39;avoir terminé :</p><ul><li><a href="./../start/quick-install/">Installation Rapide</a> : Effectuer l&#39;installation du plugin et la première authentification</li><li><a href="./../start/first-request/">Première Requête</a> : Envoyer avec succès la première requête modèle</li></ul></div><h2 id="parcours-d-apprentissage" tabindex="-1">Parcours d&#39;Apprentissage <a class="header-anchor" href="#parcours-d-apprentissage" aria-label="Permalink to &quot;Parcours d&#39;Apprentissage&quot;">​</a></h2><p>Suivez cet ordre d&#39;apprentissage pour maîtriser progressivement les fonctionnalités de la plateforme :</p><h3 id="_1-modeles-disponibles" tabindex="-1">1. <a href="./available-models/">Modèles Disponibles</a> <a class="header-anchor" href="#_1-modeles-disponibles" aria-label="Permalink to &quot;1. [Modèles Disponibles](./available-models/)&quot;">​</a></h3><p>Découvrez tous les modèles disponibles et leurs configurations de variantes</p><ul><li>Découvrez Claude Opus 4.5, Sonnet 4.5 et Gemini 3 Pro/Flash</li><li>Comprenez la distribution des modèles dans les deux pools de quotas Antigravity et Gemini CLI</li><li>Maîtrisez l&#39;utilisation du paramètre <code>--variant</code></li></ul><h3 id="_2-systeme-double-quota" tabindex="-1">2. <a href="./dual-quota-system/">Système Double Quota</a> <a class="header-anchor" href="#_2-systeme-double-quota" aria-label="Permalink to &quot;2. [Système Double Quota](./dual-quota-system/)&quot;">​</a></h3><p>Comprenez le fonctionnement du système double quota Antigravity et Gemini CLI</p><ul><li>Découvrez comment chaque compte possède deux pools de quotas Gemini indépendants</li><li>Activez la configuration automatique de fallback pour doubler les quotas</li><li>Spécifiez explicitement l&#39;utilisation du pool de quotas pour un modèle donné</li></ul><h3 id="_3-google-search-grounding" tabindex="-1">3. <a href="./google-search-grounding/">Google Search Grounding</a> <a class="header-anchor" href="#_3-google-search-grounding" aria-label="Permalink to &quot;3. [Google Search Grounding](./google-search-grounding/)&quot;">​</a></h3><p>Activez Google Search pour les modèles Gemini afin d&#39;améliorer l&#39;exactitude factuelle</p><ul><li>Permettez à Gemini de rechercher des informations en temps réel sur le Web</li><li>Ajustez le seuil de recherche pour contrôler la fréquence des recherches</li><li>Choisissez la configuration appropriée selon les besoins de la tâche</li></ul><h3 id="_4-modeles-thinking" tabindex="-1">4. <a href="./thinking-models/">Modèles Thinking</a> <a class="header-anchor" href="#_4-modeles-thinking" aria-label="Permalink to &quot;4. [Modèles Thinking](./thinking-models/)&quot;">​</a></h3><p>Maîtrisez la configuration et l&#39;utilisation des modèles Thinking Claude et Gemini 3</p><ul><li>Configurez le thinking budget de Claude</li><li>Utilisez les thinking levels de Gemini 3 (minimal/low/medium/high)</li><li>Comprenez la stratégie de conservation des blocs de pensée et interleaved thinking</li></ul><h2 id="prochaines-etapes" tabindex="-1">Prochaines Étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines Étapes&quot;">​</a></h2><p>Après avoir terminé ce chapitre, vous pouvez continuer à apprendre :</p><ul><li><a href="./../advanced/multi-account-setup/">Configuration Multi-Comptes</a> : Configurez plusieurs comptes Google pour réaliser la mise en pool des quotas et l&#39;équilibrage de charge</li><li><a href="./../advanced/account-selection-strategies/">Stratégies de Sélection de Comptes</a> : Maîtrisez les meilleures pratiques des trois stratégies sticky, round-robin et hybrid</li><li><a href="./../advanced/configuration-guide/">Guide de Configuration</a> : Maîtrisez toutes les options de configuration pour personnaliser le comportement du plugin selon vos besoins</li></ul>',21)])])}const h=i(l,[["render",r]]);export{m as __pageData,h as default};
